UPDATE docs SET content = '{"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"Troubleshooting Hub"}]},{"type":"paragraph","content":[{"type":"text","text":"Comprehensive guide to diagnosing and fixing issues with ARESLib, from development problems to competition pit debugging."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Quick Diagnostics"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"LED Status Indicator"}]},{"type":"paragraph","content":[{"type":"text","text":"Your controller LED provides immediate feedback on robot status:"}]},{"type":"codeBlock","attrs":{"language":"mermaid"},"content":[{"type":"text","text":"flowchart TD\n    Start[Check Controller LED] --> Green{Green?}\n    Green -->|Yes| Healthy[All Systems OK]\n    Green -->|No| Red{Red?}\n    Red -->|Yes| Critical[Critical Fault]\n    Red -->|No| Yellow{Yellow?}\n    Yellow -->|Yes| Warning[Non-Critical Fault]\n    Yellow -->|No| Off{Off?}\n    Off -->|Yes| NoConnection[No Connection]\n    Off -->|No| Blue{Blue?}\n    Blue -->|Yes| Simulation[Simulation Mode]\n    Blue -->|No| Unknown[Unknown State]\n\n    style Healthy fill:#22c55e\n    style Critical fill:#ef4444\n    style Warning fill:#eab308\n    style NoConnection fill:#6b7280\n    style Simulation fill:#3b82f6\n    style Unknown fill:#a855f7\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Common LED States"}]},{"type":"paragraph","content":[{"type":"text","text":"LED Color Meaning Action Required ???? Green All systems operational None - robot is ready ???? Red Critical fault detected Check hardware connections immediately ???? Yellow Non-critical warning Monitor performance, check logs ???? Blue Simulation mode active Normal for development ??? Off No controller connection Check gamepad/USB connection ???? Purple Low battery Replace controller batteries"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Competition Pit Debugging"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Pre-Match Checklist"}]},{"type":"codeBlock","attrs":{"language":"mermaid"},"content":[{"type":"text","text":"flowchart TD\n    Start[Match Starting Soon] --> Power[Power On Robot]\n    Power --> Connection{Controller Connected?}\n    Connection -->|No| Connect[Connect Gamepad]\n    Connection -->|Yes| LED{LED Status}\n    LED --> Red[Red LED?]\n    LED --> Green[Green LED?]\n\n    Red --> Hardware[Check Hardware Connections]\n    Hardware --> Retry[Power Cycle Robot]\n\n    Green --> Auto{Autonomous Working?}\n    Auto -->|No| AutoDebug[Check Auto Configuration]\n    Auto -->|Yes| Teleop{Teleop Working?}\n\n    Teleop -->|No| TeleopDebug[Check Command Bindings]\n    Teleop -->|Yes| Ready[Ready for Match!]\n\n    style Ready fill:#22c55e\n    style Hardware fill:#ef4444\n    style AutoDebug fill:#eab308\n    style TeleopDebug fill:#eab308\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Quick Fixes (Pit Side)"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"Hardware Issues"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Motor Not Responding:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Check AdvantageScope for motor faults\n// Verify CAN address matches hardwareMap\n// Test motor with basic OpMode first\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Encoder Not Reading:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Check encoder cable connection\n// Verify encoder type matches configuration\n// Look for \"Encoder Fault\" in AdvantageScope\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Servo Not Moving:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Verify servo PWM port\n// Check servo voltage (5V vs 6V)\n// Test servo calibration\n"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"Software Issues"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Robot Not Moving:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Check if default command is scheduled\n// Verify gamepad bindings are configured\n// Look for command scheduler errors in log\n"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Autonomous Not Running:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Verify autonomous OpMode is selected\n// Check autonomous command is scheduled in autoInit()\n// Test path following in simulation first\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Common Error Messages"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Build Errors"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"\"Cannot find symbol: DriveIO\""}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Cause:"},{"type":"text","text":" IO interface not imported or doesn''t exist"}]},{"type":"reveal","attrs":{"summary":"Solution:"},"content":[{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Make sure IO interface exists\npublic interface DriveIO {\n    // Interface methods\n}\n\n// Import in subsystem\nimport org.yourteam.lib.io.DriveIO;\n"}]}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"\"NoSuchMethodException: updateInputs\""}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Cause:"},{"type":"text","text":" "},{"type":"text","marks":[{"type":"code"}],"text":"@AutoLog"},{"type":"text","text":" annotation processor not running"}]},{"type":"reveal","attrs":{"summary":"Solution:"},"content":[{"type":"codeBlock","attrs":{"language":"gradle"},"content":[{"type":"text","text":"// Ensure annotation processing is enabled in build.gradle\nandroid {\n    compileOptions {\n        annotationProcessorEnabled true\n    }\n}\n\n// Clean and rebuild\n./gradlew clean build\n"}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Runtime Errors"}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"\"NullPointerException in Command\""}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Cause:"},{"type":"text","text":" Subsystem not initialized before command"}]},{"type":"reveal","attrs":{"summary":"Solution:"},"content":[{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Bad: Subsystem not initialized\npublic class RobotContainer {\n    private DriveSubsystem drive;\n    // drive is null!\n\n    public RobotContainer() {\n        // Forgot to initialize drive\n    }\n}\n\n// Good: Initialize subsystems first\npublic class RobotContainer {\n    private final DriveSubsystem drive;\n\n    public RobotContainer() {\n        drive = new DriveSubsystem(new DriveIOReal());\n        // Now drive is not null\n    }\n}\n"}]}]},{"type":"heading","attrs":{"level":4},"content":[{"type":"text","text":"\"Robot stuck in initialization loop\""}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Cause:"},{"type":"text","text":" Command blocking in "},{"type":"text","marks":[{"type":"code"}],"text":"initialize()"},{"type":"text","text":" method"}]},{"type":"reveal","attrs":{"summary":"Solution:"},"content":[{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Bad: Blocking call\n@Override\npublic void initialize() {\n    Thread.sleep(1000); // NEVER do this!\n}\n\n// Good: Use timer or state\nprivate final Timer timer = new Timer();\n\n@Override\npublic void initialize() {\n    timer.reset();\n    timer.start();\n}\n\n@Override\npublic boolean isFinished() {\n    return timer.hasElapsed(1.0);\n}\n"}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Performance Issues"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Robot Running Slowly"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Symptoms:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Loop frequency below 200Hz"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Laggy response to controls"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"GC pauses visible in AdvantageScope"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Solutions:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Bad: Creating objects in loop\n@Override\npublic void periodic() {\n    List<Double> values = new ArrayList<>(); // BAD!\n    values.add(sensor.getValue());\n}\n\n// Good: Reuse objects\nprivate final List<Double> values = new ArrayList<>();\n\n@Override\npublic void periodic() {\n    values.clear();\n    values.add(sensor.getValue());\n}\n"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"High Memory Usage"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Symptoms:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Memory increasing over time"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Robot slows down after extended use"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"\"Out of memory\" errors"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Solutions:"}]},{"type":"codeBlock","attrs":{"language":"java"},"content":[{"type":"text","text":"// Bad: Not clearing collections\nprivate final List<Object> cache = new ArrayList<>();\n\npublic void addToCache(Object obj) {\n    cache.add(obj); // Never cleared!\n}\n\n// Good: Manage memory properly\nprivate final List<Object> cache = new ArrayList<>();\n\npublic void addToCache(Object obj) {\n    if (cache.size() > 100) {\n        cache.clear(); // Prevent memory leak\n    }\n    cache.add(obj);\n}\n"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"AdvantageScope Debugging"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Key Metrics to Monitor"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Drive Train:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Loop frequency (should be ~250Hz)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Motor currents (watch for spikes)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Odometry drift (compare to reality)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Path following error"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Mechanisms:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Position vs target"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Motor voltage output"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Encoder velocity"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Limit switch states"}]}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Vision:"}]},{"type":"bulletList","content":[{"type":"listItem","conten